update public.lessons l set enhancements = $ench${"industryStory":"A tester assumed AI \"looked up\" answers like a search engine and was baffled when it confidently invented an API field. Understanding that an LLM predicts likely text — it does not retrieve facts — is what makes its behaviour (and its mistakes) make sense.","visualAid":{"type":"flow","title":"How an LLM responds (simplified)","steps":[{"label":"Your prompt","detail":"text in"},{"label":"Predicts","detail":"most likely next words"},{"label":"Generates","detail":"fluent response"},{"label":"You verify","detail":"against reality"}],"caption":"It predicts plausible text — it does not \"know\" your system."},"davidTip":"Once you grasp that an LLM predicts plausible text rather than retrieving verified facts, hallucinations stop being surprising — and you build the habit of verifying specifics every time.","miniChallenge":"In one or two sentences, explain to a colleague why an AI can sound completely confident and still be wrong.","modelAnswer":"## Example\n\"It generates the most likely-sounding text based on patterns, not verified facts. Confidence is just fluent wording — so a precise-sounding detail can still be invented, which is why we verify.\""}$ench$::jsonb
from public.modules m join public.courses c on c.id = m.course_id
where l.module_id = m.id and c.slug = 'ai-for-qa-testers'
  and m.module_number = 2 and l.lesson_number = 1;

update public.lessons l set enhancements = $ench${"industryStory":"A tester pasted a one-line prompt with no context and got generic rubbish; a colleague gave the model the story, the rules and an example, and got usable output. Same tool — the difference was prompt, context and how much the model had to work with.","visualAid":{"type":"comparison","title":"Prompt · context · tokens","headers":["Term","Plain meaning"],"rows":[["Prompt","What you ask"],["Context","The info you give it to work from"],["Tokens","Chunks of text — there is a limit per conversation"]]},"davidTip":"More relevant context usually means better output — but there is a token limit, so be relevant, not exhaustive. Give the model what it needs to do the task well, and nothing confidential.","miniChallenge":"Take a vague prompt (\"write some tests\") and list three pieces of context that would make the output far more useful.","modelAnswer":"## Example\nContext to add: the feature and its rules (e.g. password 8–20 chars), the format you want (a table), and a constraint (\"do not invent fields\"). With those, the output is specific and usable."}$ench$::jsonb
from public.modules m join public.courses c on c.id = m.course_id
where l.module_id = m.id and c.slug = 'ai-for-qa-testers'
  and m.module_number = 2 and l.lesson_number = 2;

update public.lessons l set enhancements = $ench${"industryStory":"AI stated an endpoint returned a \"discountCode\" field. A tester built a test around it — but the field never existed. That invented detail is a hallucination, and catching them is now a core QA skill.","badGood":{"label":"trusting AI output","bad":"AI says the API returns \"loyaltyPoints\" — you write a test asserting it.","good":"AI says the API returns \"loyaltyPoints\" — you check the real API docs/response first, find it does not exist, and drop it."},"davidTip":"Be most sceptical of precise specifics — field names, numbers, rules, citations. The more exact and confident the detail, the more important it is to verify against the real spec or system.","miniChallenge":"Ask AI about a system you know well and deliberately find one inaccuracy. Note how confidently it presented the wrong detail.","modelAnswer":"## Example\nI asked about a login API and it described a \"rememberMe\" parameter we do not have. It stated it as fact. Verifying against our docs caught it — exactly the habit to keep.","resourcePreview":{"name":"AI Hallucination Checklist","purpose":"A quick checklist to catch confident-but-false AI output before it reaches your testing.","whenToUse":"Run through it whenever AI gives you specifics you plan to rely on.","formats":["PDF","DOCX"]}}$ench$::jsonb
from public.modules m join public.courses c on c.id = m.course_id
where l.module_id = m.id and c.slug = 'ai-for-qa-testers'
  and m.module_number = 2 and l.lesson_number = 3;

update public.lessons l set enhancements = $ench${"industryStory":"A tester almost pasted a real customer record into a public AI tool to \"speed things up\". Responsible, secure AI use is now a professional expectation — and a single data leak can be career-defining.","visualAid":{"type":"comparison","title":"Responsible & secure AI use","headers":["Do","Do not"],"rows":[["Use synthetic / dummy data","Paste secrets, customer or production data"],["Verify specifics against reality","Trust output as fact"],["Use approved tools","Share proprietary code on public tools"]]},"davidTip":"A simple test before sending any prompt: \"would I be comfortable if this were public?\" If not, do not send it. Being able to articulate responsible AI use is genuinely valued in interviews now.","miniChallenge":"Write your three-sentence \"responsible AI\" rule covering data, verification and accountability.","modelAnswer":"## Example\n\"I only use approved tools and never paste real customer or production data. I treat AI output as a draft I verify against the real system. I stay accountable for the result as if I produced it myself.\"","resourcePreview":{"name":"AI Usage Policy Template","purpose":"An adaptable policy for using AI responsibly in QA work.","whenToUse":"Adapt it for yourself or to propose to your team.","formats":["PDF","DOCX"]}}$ench$::jsonb
from public.modules m join public.courses c on c.id = m.course_id
where l.module_id = m.id and c.slug = 'ai-for-qa-testers'
  and m.module_number = 2 and l.lesson_number = 4;

update public.lessons l set enhancements = $ench${"davidTip":"For this assignment, show you understand both how LLMs behave and how to use them safely. Pairing \"why it hallucinates\" with \"how I verify and protect data\" is exactly the balanced competence employers look for.","miniChallenge":"Before the full assignment, run one prompt and note: the prompt, the output, and one thing you would verify before trusting it.","managersReview":{"intro":"If I received this assignment as a QA lead, I would look for:","strengths":["Clear, simple grasp of how LLMs work","Awareness of hallucinations and limits","Concrete data-safety and verification rules"],"gaps":["Treating AI as a fact source","No data-handling rules","No verification step"],"improvements":["Explain prediction vs retrieval","State your data rules","Describe how you verify specifics"]}}$ench$::jsonb
from public.modules m join public.courses c on c.id = m.course_id
where l.module_id = m.id and c.slug = 'ai-for-qa-testers'
  and m.module_number = 2 and l.lesson_number = 5;

